#include<bits/stdc++.h>
using namespace std;
char explore[1002][1002];
bool step[1002][1002];
int t,n,m,k,x,y,d,ans=1;
int main(){
	cin>>t;
	for(int tt=1;tt<=t;tt++){
		cin>>n>>m>>k;
		cin>>x>>y>>d;
  		step[x][y] = 1; // 加上这一行就好啦
		for(int i=1;i<=n;i++){
			for(int j=1;j<=m;j++){
				cin>>explore[i][j];
			}
		}
		for(int i=1;i<=k;i++){
			int xx=x,yy=y;
			if(d==0) yy++;
			if(d==1) xx++;
			if(d==2) yy--;
			if(d==3) xx--;
			if(xx<1||xx>n||yy<1||yy>m||explore[xx][yy]=='x') d=(d+1)%4;
			else{
				if(step[xx][yy]==0) step[xx][yy]=1,ans++;
				x=xx,y=yy;
			}
		}
		cout<<ans<<endl;
		ans=1;
		for(int i=1;i<=n;i++){
			for(int j=1;j<=m;j++){
				step[i][j]=0;
			}
		}
	}
	return 0;
}
